/**
 * @summary Obtener logs de auditoría (admin)
 */
export const adminGetAuditLogsQueryLimitDefault = 50;

export const AdminGetAuditLogsQueryParams = zod.object({
  "game_id": zod.coerce.number().optional(),
  "user_id": zod.coerce.number().optional(),
  "action": zod.coerce.string().optional(),
  "limit": zod.coerce.number().default(adminGetAuditLogsQueryLimitDefault)
})

export const AdminGetAuditLogsResponseItem = zod.object({
  "id": zod.number(),
  "action": zod.string().describe('Tipo de acción (card_purchase, bingo_claim, number_called, winner_validated, etc.)'),
  "user_id": zod.number().nullable(),
  "game_id": zod.number().nullable(),
  "card_id": zod.number().nullish(),
  "details": zod.object({

}).passthrough().describe('JSON con detalles de la acción'),
  "ip_address": zod.string().nullish(),
  "created_at": zod.coerce.date()
})
export const AdminGetAuditLogsResponse = zod.array(AdminGetAuditLogsResponseItem)


